# DependencyLicenseChecker.Tests.ps1
# Pester tests for the Dependency License Checker module.
# Following red/green TDD: each test block was written before its implementation.

BeforeAll {
    . "$PSScriptRoot/DependencyLicenseChecker.ps1"
}

Describe "Parse-DependencyManifest" {

    Context "package.json parsing" {

        BeforeAll {
            # Test fixture: a minimal package.json
            $script:fixtureDir = Join-Path $PSScriptRoot "test-fixtures"
            if (-not (Test-Path $script:fixtureDir)) {
                New-Item -ItemType Directory -Path $script:fixtureDir | Out-Null
            }

            $packageJson = @{
                name         = "test-project"
                version      = "1.0.0"
                dependencies = @{
                    "express" = "^4.18.2"
                    "lodash"  = "4.17.21"
                }
                devDependencies = @{
                    "jest" = "^29.0.0"
                }
            } | ConvertTo-Json -Depth 5

            $script:packageJsonPath = Join-Path $script:fixtureDir "package.json"
            Set-Content -Path $script:packageJsonPath -Value $packageJson
        }

        It "Should return dependency objects with Name and Version" {
            $deps = Parse-DependencyManifest -Path $script:packageJsonPath
            $deps | Should -Not -BeNullOrEmpty
            $deps[0].PSObject.Properties.Name | Should -Contain "Name"
            $deps[0].PSObject.Properties.Name | Should -Contain "Version"
        }

        It "Should parse all dependencies from package.json" {
            $deps = Parse-DependencyManifest -Path $script:packageJsonPath
            $names = $deps | ForEach-Object { $_.Name }
            $names | Should -Contain "express"
            $names | Should -Contain "lodash"
        }

        It "Should include devDependencies" {
            $deps = Parse-DependencyManifest -Path $script:packageJsonPath
            $names = $deps | ForEach-Object { $_.Name }
            $names | Should -Contain "jest"
        }

        It "Should strip version prefixes like ^ and ~" {
            $deps = Parse-DependencyManifest -Path $script:packageJsonPath
            $express = $deps | Where-Object { $_.Name -eq "express" }
            $express.Version | Should -Be "4.18.2"
        }
    }
}

